#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""nodetest — generated by ROS2 IDE Package Wizard"""

import rclpy
from rclpy.node import Node
from geometry_msgs.msg import Twist

class nodetest(Node):
    def __init__(self):
        super().__init__('nodetest_node')
        self.pub_ = self.create_publisher(
            Twist,
            '/cmd_vel',
            10)
        self.timer_ = self.create_timer(0.1, self.timer_callback)
        self.get_logger().info('nodetest started')

    def timer_callback(self):
        msg = Twist()
        msg.linear.x = 0.0
        msg.angular.z = 0.0
        self.pub_.publish(msg)


def main(args=None):
    rclpy.init(args=args)
    node = nodetest()
    try:
        rclpy.spin(node)
    except KeyboardInterrupt:
        pass
    finally:
        node.destroy_node()
        rclpy.shutdown()


if __name__ == '__main__':
    main()
